function solve(s) {
    const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);

    // Step 1: Analysis Phase
    // Store counts, first indices, and identify all vowel occurrences
    const counts = new Map();
    const firstIndex = new Map();

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (VOWELS.has(char)) {

            // Count frequency
            counts.set(char, (counts.get(char) || 0) + 1);

            // Record first index
            if (!firstIndex.has(char)) {
                firstIndex.set(char, i);
            }
        }
    }

    // Step 2: Sorting Phase

    // Get unique vowels present
    const uniqueVowels = Array.from(counts.keys());

    // Sort unique vowels based on criteria:
    // 1. Frequency (non-increasing / descending)
    // 2. First Appearance Index (ascending)
    uniqueVowels.sort((v1, v2) => {
        const freq1 = counts.get(v1);
        const freq2 = counts.get(v2);

        // Primary sort: Frequency descending (freq2 - freq1)
        if (freq1 !== freq2) {
            return freq2 - freq1; 
        }

        // Secondary sort: First Index ascending (index1 - index2)
        const index1 = firstIndex.get(v1);
        const index2 = firstIndex.get(v2);
        return index1 - index2;
    });

    // Generate the final sorted vowel sequence
    const sortedVowelSequence = [];
    for (const vowel of uniqueVowels) {
        const count = counts.get(vowel);
        for (let k = 0; k < count; k++) {
            sortedVowelSequence.push(vowel);
        }
    }

    // Step 3: Reconstruction Phase
    const resultChars = Array(s.length);
    let vowelPtr = 0;

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (VOWELS.has(char)) {
            // Replace original vowel with the next vowel from the sorted sequence
            resultChars[i] = sortedVowelSequence[vowelPtr];
            vowelPtr++;
        } else {
            // Keep consonants as they are
            resultChars[i] = char;
        }
    }

    return resultChars.join('');
}
```

